Bash("C:\\Users\\newpa\\Downloads\\evidly-demo-final\\evidly-app-main\\_gen_sitemap.js" << 'SCRIPT'
const fs = require\('fs'\);
const content = fs.readFileSync\('src/pages/public/CityPage.jsx', 'utf8'\);
const match = content.match\(/var _c=\\{\([\\s\\S]*?\)\\};/\);
if \(!match\) { console.error\('Could not find _c mapping'\); process.exit\(1\); }
const lines = match[1].split\('\\n'\);
const cities = [];
for \(const line of lines\) {
  const arrayMatch = line.match\(/\\[\([^\\]]+\)\\]/\);
  if \(arrayMatch\) {
    const slugs = arrayMatch[1].match\(/"\([^"]+\)"/g\);
    if \(slugs\) {
      for \(const s of slugs\) {
        cities.push\(s.replace\(/"/g, ''\)\);
      }
    }
  }
}
cities.sort\(\);
let xml = '  <!-- City Pages -->\\n';
for \(const city of cities\) {
  xml += '  <url><loc>https://getevidly.com/city/' + city + '</loc><lastmod>2026-03-05</lastmod><changefreq>monthly</changefreq><priority>0.6</priority></url>\\n';
}
xml += '\\nTotal cities: ' + cities.length;
fs.writeFileSync\('_sitemap_cities.txt', xml\);
console.log\('Done. Total cities: ' + cities.length\);
SCRIPT)
